  // Get tasks for a specific column
  const getTasksForColumn = useCallback((columnId: string) => {
    return localTasks.filter(task => task.column === columnId);
  }, [localTasks]);

  // Calculate statistics
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter(t => t.column === (props.columns.find(c => c.name?.toLowerCase().includes('done'))?.id || 'done')).length;

