            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              style={{ width: '200px' }}
            />
          </Row>
        </Card>

        {/* Kanban board */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns && props.columns.map(column => {
