            const isAddFormVisible = showAddForm === column.id;

            return (
              <Box
                key={column.id}
                style={{ flex: '1 1 300px', minWidth: '300px' }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column header */}
                  <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border={true}>
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Heading level={5} style={{ margin: 0 }}>
                        {column.name}
                      </Heading>
                      <Badge variant="secondary" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>
                  </Card>

                  {/* Task list */}
                  <Stack gap="var(--ggui-spacing-3)" style={{ minHeight: '400px' }}>
                    {columnTasks.length > 0 ? (
                      columnTasks.map(task => (
                        <TaskCard
                          key={task.id}
