                    )}
                  </Stack>

                  {/* Add task form or button */}
                  {isAddFormVisible ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border={true}>
                      <Stack gap="var(--ggui-spacing-2)">
