// Helper function to get category color
const getCategoryColor = (category?: string): string => {
  const categoryColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-100)',
    'alkaline earth metal': 'var(--ggui-color-info-100)',
    'transition metal': 'var(--ggui-color-warning-100)',
    'basic metal': 'var(--ggui-color-error-100)',
    'semimetal': 'var(--ggui-color-success-100)',
    'nonmetal': 'var(--ggui-color-primary-50)',
    'halogen': 'var(--ggui-color-warning-50)',
    'noble-gas': 'var(--ggui-color-info-50)',
    'lanthanide': 'var(--ggui-color-primary-200)',
    'actinide': 'var(--ggui-color-success-200)',
  };
  return categoryColors[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
};

const getCategoryBorder = (category?: string): string => {
  const categoryBorders: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-300)',
    'alkaline earth metal': 'var(--ggui-color-info-300)',
    'transition metal': 'var(--ggui-color-warning-300)',
    'basic metal': 'var(--ggui-color-error-300)',
    'semimetal': 'var(--ggui-color-success-300)',
    'nonmetal': 'var(--ggui-color-primary-200)',
    'halogen': 'var(--ggui-color-warning-200)',
    'noble-gas': 'var(--ggui-color-info-200)',
    'lanthanide': 'var(--ggui-color-primary-300)',
    'actinide': 'var(--ggui-color-success-300)',
  };
  return categoryBorders[category?.toLowerCase() || ''] || 'var(--ggui-color-outline)';
};

// Helper: Get unique categories for legend
const getUniqueCategoriesWithOrder = (elements: Props['elements']): Array<{category: string; color: string; border: string}> => {
   const categoryOrder = ['alkali metal', 'alkaline earth metal', 'transition metal', 'basic metal', 'semimetal', 'nonmetal', 'halogen', 'noble-gas', 'lanthanide', 'actinide'];
  const seen = new Set<string>();
  const result: Array<{category: string; color: string; border: string}> = [];

  // First add ordered categories that appear in elements
  for (const cat of categoryOrder) {
    if (elements.some(e => e.category?.toLowerCase() === cat) && !seen.has(cat)) {
      seen.add(cat);
      result.push({ category: cat, color: getCategoryColor(cat), border: getCategoryBorder(cat) });
    }
  }

  // Then add any remaining categories not in order
  for (const elem of elements) {
    const cat = elem.category?.toLowerCase() || '';
    if (cat && !seen.has(cat)) {
      seen.add(cat);
      result.push({ category: cat, color: getCategoryColor(cat), border: getCategoryBorder(cat) });
    }
  }

  return result;
};

