/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };



// Helper function to group consecutive messages from same sender
function groupMessages(messages: Array<{ sender?: string; text?: string; timestamp?: string }>) {
  const grouped: Array<{
    sender?: string;
    messages: Array<{ text?: string; timestamp?: string }>;
  }> = [];

  for (const msg of messages) {
    if (grouped.length > 0 && grouped[grouped.length - 1].sender === msg.sender) {
      grouped[grouped.length - 1].messages.push({ text: msg.text, timestamp: msg.timestamp });
    } else {
      grouped.push({ sender: msg.sender, messages: [{ text: msg.text, timestamp: msg.timestamp }] });
    }
  }

  return grouped;
}

// Helper component for individual message
function MessageBubble({ sender, text, timestamp, isCurrentUser }: { sender?: string; text?: string; timestamp?: string; isCurrentUser: boolean }) {
  const formatTime = (ts?: string) => {
    if (!ts) return '';
    try {
      const date = new Date(ts);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return ts;
    }
  };

  return (
    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)" justify={isCurrentUser ? 'end' : 'start'} style={{ marginBottom: 'var(--ggui-spacing-2)' }}>
      {!isCurrentUser && sender && <Avatar name={sender} size="sm" shape="circle" />}
      <Stack gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
        {!isCurrentUser && sender && <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="xs">{sender}</Text>}
        <Card
          padding="var(--ggui-spacing-3)"
          shadow="none"
          border={false}
          radius="md"
          style={{
            background: isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)',
            maxWidth: '70%',
            wordWrap: 'break-word',
          }}
        >
          <Text color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'} variant="body">{text || ''}</Text>
        </Card>
        {timestamp && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">{formatTime(timestamp)}</Text>}
      </Stack>
    </Stack>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const messageStream = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typingStream = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (messageStream.latest) {
      setAllMessages((prev) => [...prev, messageStream.latest!]);
    }
  }, [messageStream.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typingStream.latest) {
      if (typingStream.latest.active && typingStream.latest.sender !== props.currentUser) {
        setTypingUser(typingStream.latest.sender || 'Someone');
      } else if (!typingStream.latest.active) {
        setTypingUser(null);
      }
    }
  }, [typingStream.latest, props.currentUser]);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText, timestamp });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  const handleKeyPress = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-0)" center>
      <Card shadow="md" radius="lg" padding="0" border style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <Box padding="var(--ggui-spacing-4)" borderBottom style={{ borderBottomColor: 'var(--ggui-color-outlineVariant)', borderBottomWidth: '1px' }}>
          <Row justify="between" align="center">
            <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>
          {typingUser && (
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
              <Spinner size={16} color="var(--ggui-color-primary-600)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">{typingUser} is typing...</Text>
            </Stack>
          )}
        </Box>

        {/* Messages area */}
        <Box
          padding="var(--ggui-spacing-4)"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-2)',
          }}
        >
          {allMessages.length === 0 ? (
            <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation!</Text>
            </Box>
          ) : (
            <>
              {groupMessages(allMessages).map((group, groupIdx) => (
                <Stack key={groupIdx} gap="var(--ggui-spacing-1)" align={group.sender === props.currentUser ? 'end' : 'start'}>
                  {group.messages.map((msg, msgIdx) => {
                    const isCurrentUser = group.sender === props.currentUser;
                    return (
                      <MessageBubble
                        key={`${groupIdx}-${msgIdx}`}
                        sender={groupIdx === 0 || group.messages[msgIdx - 1] !== msg ? group.sender : undefined}
                        text={msg.text}
                        timestamp={msg.timestamp}
                        isCurrentUser={isCurrentUser}
                      />
                    );
                  })}
                </Stack>
              ))}
              <div ref={messagesEndRef} />
            </>
          )}
        </Box>

        {/* Input area */}
        <Box
          padding="var(--ggui-spacing-4)"
          style={{
            borderTopWidth: '1px',
            borderTopColor: 'var(--ggui-color-outlineVariant)',
            borderTopStyle: 'solid',
          }}
        >
          <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2)">
            <Box style={{ flex: 1 }}>
              <FormField label="Message">
                <TextArea
                  placeholder="Type your message here..."
                  value={messageText}
                  onChange={setMessageText}
                  onKeyDown={handleKeyPress}
                  rows={2}
                />
              </FormField>
            </Box>
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!messageText.trim()}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

