  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: track displayed stocks and recently updated symbols
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const [, setForceUpdate] = useState(0); // Force re-render for real-time timestamp

  // Merge price updates from stream into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol) {
        // Mark this symbol as updating (for flash animation)
        setUpdatingSymbols((prev) => new Set([...prev, update.symbol!]));

        // Merge the update into displayStocks
        setDisplayStocks((prev) =>
          prev.map((stock) =>
            stock.symbol === update.symbol
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          )
        );

        // Update the timestamp
        setLastUpdated(new Date());

        // Remove the updating flag after animation completes (600ms for ggui-flash)
        if (updateTimeoutRef.current) {
          clearTimeout(updateTimeoutRef.current);
        }
        updateTimeoutRef.current = setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
        }, 600);
      }
    }
  }, [priceUpdate.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
      }
    };
  }, []);

  // Update timestamp every second for real-time display
  useEffect(() => {
    const interval = setInterval(() => {
      setForceUpdate((prev) => prev + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Determine market status color and text
  const statusInfo = useMemo(() => {
    const status = marketStatus.latest?.status ?? 'unknown';
    switch (status) {
      case 'open':
        return { color: 'var(--ggui-color-success-600)', label: 'Market Open' };
      case 'closed':
        return { color: 'var(--ggui-color-error-600)', label: 'Market Closed' };
      case 'pre-market':
        return { color: 'var(--ggui-color-warning-600)', label: 'Pre-Market' };
      case 'after-hours':
        return { color: 'var(--ggui-color-info-600)', label: 'After Hours' };
      default:
        return { color: 'var(--ggui-color-onSurfaceVariant)', label: 'Unknown' };
    }
  }, [marketStatus.latest?.status]);

  // Format last updated timestamp
  const lastUpdatedText = useMemo(() => {
    const now = new Date();
    const diffSeconds = Math.floor((now.getTime() - lastUpdated.getTime()) / 1000);
    if (diffSeconds < 60) {
      return 'just now';
    } else if (diffSeconds < 3600) {
      return `${Math.floor(diffSeconds / 60)} minute${Math.floor(diffSeconds / 60) !== 1 ? 's' : ''} ago`;
    } else {
      return lastUpdated.toLocaleTimeString();
    }
  }, [lastUpdated]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header: Title and Last Updated */}
        <Row justify="between" align="center">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Badge variant={marketStatus.latest?.status === 'open' ? 'success' : 'default'}>
              {statusInfo.label}
            </Badge>
          </Stack>
          <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated:&nbsp;
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-primary-600)" weight="semibold">
              {lastUpdatedText}
            </Text>
          </Stack>
        </Row>

         {/* Responsive Stock Grid */}
         <Box
           is="ul"
           style={{
             display: 'grid',
             gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
             gap: 'var(--ggui-spacing-4)',
             listStyle: 'none',
             padding: 0,
             margin: 0,
             '@media (min-width: 768px)': {
               gridTemplateColumns: 'repeat(3, 1fr)',
             },
             '@media (max-width: 480px)': {
               gridTemplateColumns: '1fr',
             },
           } as React.CSSProperties}
         >
           {displayStocks.map((stock) => (
             <Box is="li" key={stock.symbol || 'unknown'}>
               <StockCard
                 stock={stock}
                 isUpdating={updatingSymbols.has(stock.symbol || '')}
               />
             </Box>
           ))}
         </Box>
