  // Handle back button click
  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
  }, [currentStep]);

  // Handle complete button click
  const handleComplete = useCallback(() => {
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar: selectedAvatar,
