  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [nameTouched, setNameTouched] = useState<boolean>(false);
  const [emailTouched, setEmailTouched] = useState<boolean>(false);

  const normalizedFeatureOptions = useMemo(() => (Array.isArray(props.featureOptions) ? props.featureOptions : []), [props.featureOptions]);
  const normalizedSatisfactionLabels = useMemo(() => (Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : []), [props.satisfactionLabels]);

  const nameError = nameTouched && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = emailTouched
    ? email.trim().length === 0
      ? 'Email is required.'
      : !isValidEmail(email)
        ? 'Please enter a valid email address.'
        : ''
    : '';

  const isStep1Valid = name.trim().length > 0 && isValidEmail(email);
  const isStep2Valid = satisfaction !== null && satisfaction >= 1 && satisfaction <= 5;
  const isStep3Valid = true;
  const isStep4Valid = comments.length <= 500;

  const canGoNext =
    (step === 1 && isStep1Valid) ||
    (step === 2 && isStep2Valid) ||
    (step === 3 && isStep3Valid) ||
    (step === 4 && isStep4Valid);

  const progressValue = Math.round((step / TOTAL_STEPS) * 100);

  const satisfactionOptions = useMemo(
    () =>
      [1, 2, 3, 4, 5].map((value) => ({
        value: String(value),
        label: normalizedSatisfactionLabels[value - 1] || `Rating ${value}`
      })),
    [normalizedSatisfactionLabels]
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (!canGoNext) {
      if (step === 1) {
        setNameTouched(true);
