              <Badge variant="primary">Step {step} of {TOTAL_STEPS}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Your Details</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={(value) => {
                    setName(value);
                    setNameTouched(true);
                  }}
                  required
                  error={nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    setEmailTouched(true);
                  }}
                  required
                  error={emailError}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Satisfaction Rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction !== null ? String(satisfaction) : ''}
                  onChange={(value) => setSatisfaction(Number(value))}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Feature Interests</Heading>
                {normalizedFeatureOptions.length === 0 ? (
                  <Alert variant="info" title="No feature options">
                    No feature options are currently available.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {normalizedFeatureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Additional Comments</Heading>
                <TextArea
                  label="Comments (Optional)"
                  value={comments}
                  onChange={setComments}
                  maxLength={500}
                  showCount
                  rows={6}
                  helperText="Share anything else you'd like us to know."
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" border>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                      {satisfaction !== null ? (normalizedSatisfactionLabels[satisfaction - 1] || `Rating ${satisfaction}`) : '—'}
                    </Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() ? comments.trim() : 'No comments'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Text
                as={Clickable}
                onClick={handleBack}
                color={step === 1 ? 'var(--ggui-color-onSurfaceVariant)' : 'var(--ggui-color-primary-600)'}
              >
                Back
              </Text>
              <Row gap="var(--ggui-spacing-2)">
                {step < TOTAL_STEPS && (
                  <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                    Next
                  </Button>
                )}
                {step === TOTAL_STEPS && (
                  <Button variant="primary" onClick={handleSubmit}>
                    Submit
                  </Button>
                )}
              </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

