// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




type BoardTask = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

function normalizeTask(task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, fallbackColumn: string): BoardTask {
  return {
    id: task.id || `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    title: task.title || 'Untitled Task',
    priority: task.priority || 'medium',
    assignee: task.assignee || 'NA',
    column: task.column || fallbackColumn,
    dueDate: task.dueDate || undefined,
  };
}

function getPriorityVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function getInitials(value: string): string {
  const parts = value.trim().split(' ').filter(Boolean);
  if (parts.length === 0) return 'NA';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0]}${parts[1][0]}`.toUpperCase();
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const defaultColumnId = props.columns && props.columns.length > 0 && props.columns[0]?.id ? props.columns[0].id : 'todo';
  const [boardTasks, setBoardTasks] = useState<BoardTask[]>(
    (props.tasks || []).map((task) => normalizeTask(task, defaultColumnId))
  );
  const [addFormColumn, setAddFormColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState<string>('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newAssignee, setNewAssignee] = useState<string>('');
  const [newDueDate, setNewDueDate] = useState<string>('');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState<string>('');

  useEffect(() => {
    setBoardTasks((props.tasks || []).map((task) => normalizeTask(task, defaultColumnId)));
  }, [props.tasks, defaultColumnId]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = normalizeTask(taskChanged.latest.task, defaultColumnId);
    setBoardTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => task.id !== incoming.id);
      }
      const exists = prev.some((task) => task.id === incoming.id);
      if (!exists) return [...prev, incoming];
      return prev.map((task) => (task.id === incoming.id ? { ...task, ...incoming } : task));
    });
  }, [taskChanged.latest, defaultColumnId]);

  const totalTasks = boardTasks.length;
  const completedCount = boardTasks.filter((task) => task.column === 'done').length;

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const startEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditTitle(currentTitle);
  }, []);

  const saveEdit = useCallback((taskId: string, taskColumn: string) => {
    const nextTitle = editTitle.trim();
    if (!nextTitle) return;
    const existingTask = boardTasks.find((task) => task.id === taskId);
    const updatedTask: BoardTask = {
      id: taskId,
      title: nextTitle,
      priority: existingTask?.priority || 'medium',
      assignee: existingTask?.assignee || 'NA',
      column: taskColumn,
      dueDate: existingTask?.dueDate,
    };
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? updatedTask : task)));
    taskUpdate({ action: 'edit', taskId, data: updatedTask as unknown as { column: string } });
    setEditingTaskId(null);
    setEditTitle('');
  }, [editTitle, taskUpdate, boardTasks]);
  const createTask = useCallback((targetColumn: string) => {
    const title = newTitle.trim();
    if (!title) return;
    const id = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const created: BoardTask = {
      id,
      title,
      priority: newPriority,
      assignee: newAssignee.trim() || 'NA',
      column: targetColumn || defaultColumnId,
      dueDate: newDueDate.trim() || undefined,
    };
    setBoardTasks((prev) => [...prev, created]);
    taskUpdate({ action: 'create', taskId: id, data: created as unknown as { column: string } });
    setNewTitle('');
    setNewPriority('medium');
    setNewAssignee('');
    setNewDueDate('');
    setAddFormColumn(null);
  }, [newTitle, newPriority, newAssignee, newDueDate, taskUpdate, defaultColumnId]);

  const columnOptions = (props.columns || []).map((column) => ({
    value: column.id || '',
    label: column.name || column.id || 'Column',
  }));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Task Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Track, update, and complete work in real time</Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {taskChanged.all.length > 0 && (
          <Alert variant="info" title="Live updates active">
            {taskChanged.all.length} update(s) received from collaborators
          </Alert>
        )}

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {(props.columns || []).map((column) => {
            const columnId = column.id || '';
            const tasksInColumn = boardTasks.filter((task) => task.column === columnId);
            return (
              <Card
                key={columnId || column.name}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Untitled Column'}</Heading>
                    <Badge variant="default">{tasksInColumn.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {tasksInColumn.length === 0 ? (
                      <Box
                        padding="var(--ggui-spacing-3)"
                        background="var(--ggui-color-surfaceVariant)"
                        borderRadius="var(--ggui-shape-radius-md)"
                      >
                        <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet</Text>
                      </Box>
                    ) : (
                      tasksInColumn.map((task) => (
                        <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                          <Stack gap="var(--ggui-spacing-2)">
                            {editingTaskId === task.id ? (
                              <Row gap="var(--ggui-spacing-2)" align="end">
                                <Box>
                                  <Input label="Edit task title" value={editTitle} onChange={setEditTitle} placeholder="Task title" />
                                </Box>
                                <Button variant="primary" size="sm" onPress={() => saveEdit(task.id, task.column)}>Save</Button>
                                <Button variant="ghost" size="sm" onPress={() => { setEditingTaskId(null); setEditTitle(''); }}>Cancel</Button>
                              </Row>
                            ) : (
                              <Row justify="between" align="center">
                                <Text
                                  as={Clickable}
                                  onDoubleClick={() => startEdit(task.id, task.title)}
                                  weight="medium"
                                >
                                  {task.title}
                                </Text>
                                <Button variant="ghost" size="sm" onPress={() => startEdit(task.id, task.title)}>Edit</Button>
                              </Row>
                            )}

                            <Row justify="between" align="center">
                              <Badge variant={getPriorityVariant(task.priority)}>{task.priority.toUpperCase()}</Badge>
                              <Row gap="var(--ggui-spacing-2)" align="center">
                                <Avatar name={getInitials(task.assignee)} size="xs" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{task.assignee}</Text>
                              </Row>
                            </Row>

                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                Due: {task.dueDate}
                              </Text>
                            )}

                            <Select
                              label="Move task"
                              value={task.column}
                              onChange={(value) => moveTask(task.id, value)}
                              options={columnOptions}
                            />
                          </Stack>
                        </Card>
                      ))
                    )}
                  </Stack>

                  {addFormColumn === columnId ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="none" border radius="md">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input label="Task title" value={newTitle} onChange={setNewTitle} placeholder="Enter task title" />
                        <Select
                          label="Priority"
                          value={newPriority}
                          onChange={(value) => setNewPriority(value as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Input label="Assignee" value={newAssignee} onChange={setNewAssignee} placeholder="e.g. JD" />
                        <Input label="Due date" value={newDueDate} onChange={setNewDueDate} placeholder="YYYY-MM-DD" />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onPress={() => createTask(columnId)}>Create Task</Button>
                          <Button variant="ghost" size="sm" onPress={() => setAddFormColumn(null)}>Cancel</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" onPress={() => setAddFormColumn(columnId)}>Add Task</Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

