type ProductSpec = { key: string; value: string };
type ProductReview = { author: string; rating: number; text: string; date: string };

function normalizeSpecifications(specs: unknown[] | undefined): ProductSpec[] {
  if (!Array.isArray(specs)) return [];
  return specs
    .map((item, index) => {
      if (item && typeof item === 'object') {
        const maybe = item as Record<string, unknown>;
        const key = typeof maybe.key === 'string' ? maybe.key : typeof maybe.name === 'string' ? maybe.name : `Spec ${index + 1}`;
        const value = typeof maybe.value === 'string' ? maybe.value : typeof maybe.detail === 'string' ? maybe.detail : JSON.stringify(item);
        return { key, value };
      }
      return { key: `Spec ${index + 1}`, value: String(item) };
    })
    .filter((item) => item.value.length > 0);
}

function normalizeReviews(reviews: unknown[] | undefined): ProductReview[] {
  if (!Array.isArray(reviews)) return [];
  return reviews.map((item, index) => {
    if (item && typeof item === 'object') {
      const maybe = item as Record<string, unknown>;
      return {
        author: typeof maybe.author === 'string' ? maybe.author : `Reviewer ${index + 1}`,
        rating: typeof maybe.rating === 'number' ? Math.max(1, Math.min(5, Math.round(maybe.rating))) : 0,
        text: typeof maybe.text === 'string' ? maybe.text : '',
        date: typeof maybe.date === 'string' ? maybe.date : '',
      };
    }
    return { author: `Reviewer ${index + 1}`, rating: 0, text: String(item), date: '' };
  });
}

