  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const bottomRef = useRef<HTMLDivElement | null>(null);
  const listRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) return;
    setTypingState(typing.latest);
  }, [typing.latest]);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    } else if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    (allMessages ?? []).forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text: payload.text, timestamp: payload.timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const typingLabel = useMemo(() => {
    if (!typingState?.active) return '';
    if (!typingState.sender || typingState.sender === props.currentUser) return '';
    return `${typingState.sender} is typing...`;
  }, [typingState, props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
