            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {typingLabel || 'No one is typing'}
            </Text>
          </Box>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              <Box>
                <Stack gap="var(--ggui-spacing-3)">
                  <Box>
                    <div ref={listRef} style={{ maxHeight: '50vh', overflowY: 'auto' }}>
                      <Stack gap="var(--ggui-spacing-3)">
                        {groupedMessages.length === 0 ? (
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            No messages yet
                          </Text>
                        ) : (
                          groupedMessages.map((group, groupIndex) => {
                            const isCurrentUser = group.sender === props.currentUser;
                            return (
                              <Stack
                                key={`${group.sender || 'unknown'}-${groupIndex}` }
                                align={isCurrentUser ? 'end' : 'start'}
                                gap="var(--ggui-spacing-1)"
                              >
                                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                                  {group.sender || 'Unknown'}
                                </Text>
                                {group.items.map((msg, idx) => (
                                  <Box
                                    key={`${groupIndex}-${idx}-${msg.timestamp || 't'}` }
                                    padding="var(--ggui-spacing-2)"
                                    background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                    borderRadius="var(--ggui-shape-radius-md)"
                                  >
                                    <Stack gap="var(--ggui-spacing-1)">
                                      <Text
                                        variant="body"
                                        color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                      >
                                        {msg.text || ''}
                                      </Text>
                                      <Text
                                        variant="caption"
                                        color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                      >
                                        {formatTime(msg.timestamp)}
                                      </Text>
                                    </Stack>
                                  </Box>
                                ))}
                              </Stack>
                            );
                          })
                        )}
                        <div ref={bottomRef} />
                      </Stack>
                    </div>
                  </Box>
                </Stack>
              </Box>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box style={{ flex: 1 } as React.CSSProperties}>
                  <Input
                    label="Message"
                    placeholder="Type a message..."
                    value={draft}
                    onChange={setDraft}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button variant="primary" disabled={!draft.trim()} as={Clickable} onClick={handleSend}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
