            price: priceUpdate.latest?.price ?? 0,
            change: priceUpdate.latest?.change ?? 0,
            changePercent: priceUpdate.latest?.changePercent ?? 0,
          },
        ];
      }
      return prev.map((item) => {
        if (item.symbol !== symbol) return item;
        return {
          ...item,
          price: priceUpdate.latest?.price ?? item.price,
          change: priceUpdate.latest?.change ?? item.change,
          changePercent: priceUpdate.latest?.changePercent ?? item.changePercent,
        };
      });
    });
    setLastUpdated(new Date());
    setFlashMap((prev) => ({ ...prev, [symbol]: Date.now() }));
  }, [priceUpdate.latest]);

  const displayTimestamp = useMemo(() => {
    const source = marketStatus.latest?.timestamp ? new Date(marketStatus.latest.timestamp) : lastUpdated;
    return source.toLocaleTimeString();
  }, [lastUpdated, marketStatus.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="lg">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Last Updated: {displayTimestamp}</Text>
            </Stack>
            <Badge
              variant={marketStatus.latest?.status === 'closed' ? 'error' : marketStatus.latest?.status === 'open' ? 'success' : 'warning'}
            >
              {marketStatus.latest?.status ?? 'live'}
            </Badge>
          </Row>
        </Card>

        {stocks.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data...
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocks.map((stock, index) => {
              const positive = (stock.change ?? 0) >= 0;
              const symbolKey = stock.symbol ?? `stock-${index}`;
              return (
                <Card
                  key={`${symbolKey}-${flashMap[symbolKey] ?? 0}`}
                  padding="var(--ggui-spacing-4)"
                  border
                  radius="lg"
                  shadow="sm"
                >
                  <Box
                    style={{
                      animation: 'ggui-flash 300ms ease-out',
                      border: `1px solid ${positive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)'}`,
                      borderRadius: 'var(--ggui-shape-radius-md)',
                      padding: 'var(--ggui-spacing-3)',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Heading level={3} color="var(--ggui-color-onSurface)">{stock.symbol ?? '--'}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{stock.name ?? 'Unknown Company'}</Text>
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{formatPrice(stock.price)}</Text>
                      <Row justify="between" align="center">
                        <Text
                          variant="bodySmall"
                          weight="medium"
                          color={positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                        >
                          {formatSigned(stock.change)}
                        </Text>
                        <Text
                          variant="bodySmall"
                          weight="semibold"
                          color={positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                        >
                          {positive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

