// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const getSafeAvatarOptions = (avatarOptions: string[]): string[] => {
  if (avatarOptions.length >= 4) {
    return avatarOptions.slice(0, 4);
  }

  const fallbacks = ['😀', '🚀', '🎨', '🧠'];
  const merged = [...avatarOptions];
  for (let i = 0; i < fallbacks.length && merged.length < 4; i += 1) {
    if (!merged.includes(fallbacks[i])) {
      merged.push(fallbacks[i]);
    }
  }
  return merged.slice(0, 4);
};

// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const safeAvatarOptions = useMemo(() => getSafeAvatarOptions(props.avatarOptions), [props.avatarOptions]);
  const safeRoleOptions = useMemo(() => {
    if (props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? safeAvatarOptions[0] ?? '😀');
  const [role, setRole] = useState(props.initialProfile.role ?? safeRoleOptions[0] ?? 'Developer');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? safeAvatarOptions[0] ?? '😀');
    setRole(props.initialProfile.role ?? safeRoleOptions[0] ?? 'Developer');
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  }, [props.initialProfile, safeAvatarOptions, safeRoleOptions]);

  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const isEmailValid = EMAIL_REGEX.test(trimmedEmail);
  const nameError = trimmedName.length === 0 ? 'Name is required.' : '';
  const emailError = trimmedEmail.length === 0 ? 'Email is required.' : !isEmailValid ? 'Please enter a valid email address.' : '';

  const canProceedStep1 = trimmedName.length > 0 && isEmailValid && avatar.length > 0;
  const canProceedStep2 = role.length > 0 && (theme === 'light' || theme === 'dark');
  const canProceedCurrentStep = step === 1 ? canProceedStep1 : step === 2 ? canProceedStep2 : true;

  const progressValue = (step / 3) * 100;

  const handleNext = useCallback(() => {
    setStep((current) => (current < 3 ? current + 1 : current));
  }, []);

  const handleBack = useCallback(() => {
    setStep((current) => (current > 1 ? current - 1 : current));
  }, []);

  const handleSubmit = useCallback(() => {
    if (!canProceedStep1 || !canProceedStep2) {
      return;
    }

    complete({
      name: trimmedName,
      email: trimmedEmail,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [avatar, canProceedStep1, canProceedStep2, complete, emailNotifications, role, theme, trimmedEmail, trimmedName]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={3}>Onboarding Wizard</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
              </Stack>
              <Badge variant="primary">{Math.round(progressValue)}%</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          radius="lg"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError}
                />

                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {safeAvatarOptions.map((option) => {
                      const selected = avatar === option;
                      return (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-3)"
                          radius="md"
                          border
                          hoverStyle={{ opacity: 0.9 }}
                          style={{
                            borderColor: selected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                            background: selected ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            minWidth: '56px',
                            textAlign: 'center',
                          }}
                        >
                          <Stack align="center" gap="var(--ggui-spacing-1)">
                            <Text size="2xl">{option}</Text>
                            {selected && <Badge variant="primary" size="sm">Selected</Badge>}
                          </Stack>
                        </Card>
                      );
                    })}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={safeRoleOptions.map((option) => ({ value: option, label: option }))}
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                      <Text weight="medium">{trimmedName || '-'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                      <Text weight="medium">{trimmedEmail || '-'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                      <Text weight="medium">{avatar}</Text>
                    </Row>
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                      <Text weight="medium">{role}</Text>
                    </Row>
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Email notifications</Text>
                      <Text weight="medium">{emailNotifications ? 'On' : 'Off'}</Text>
                    </Row>
                    <Row justify="between">
                      <Text color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                      <Text weight="medium">{theme === 'dark' ? 'Dark' : 'Light'}</Text>
                    </Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-5)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>

            <Row gap="var(--ggui-spacing-3)">
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canProceedCurrentStep}>
                  Next
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={handleBack}>Go Back</Button>
                  <Button variant="primary" onClick={handleSubmit} disabled={!canProceedStep1 || !canProceedStep2}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
